[
  {
    "rule_clause": "规则1: 禁止使用绝对化用语 (\"最好\"、\"第一\"、\"绝对\"、\"全网最低\"等)",
    "risk_level": "高",
    "evidence": "主播口播宣称: \"这个是市面上效果最好的!\"，\"全网最低价，绝对找不到比我家更便宜的!\"；产品claims中包含\"市面上效果最好\"、\"全网最低价\"。",
    "fix_suggestion": "立即删除上述话术与产品描述，不得使用\"最好\"、\"绝对\"、\"全网最低\"等绝对化表述，可改为\"使用者反馈很好\"、\"价格很有竞争力\"等客观描述。"
  },
  {
    "rule_clause": "规则2: 禁止对化妆品/护肤品使用效果承诺 (时间量化的功效宣称，如\"7天见效\"、\"3天白一度\")",
    "risk_level": "高",
    "evidence": "主播口播明确承诺: \"只要你坚持用7天，我保证你白一个度! 我自己用了3天就明显白了\"；产品claims中列有\"7天美白\"、\"3天见效\"。",
    "fix_suggestion": "删除所有带时间量化的功效保证，不得承诺具体见效天数和效果必达，可替换为\"有助于改善肤色\"、\"坚持使用可能使肌肤明亮\"等不承诺结果的表述。"
  },
  {
    "rule_clause": "规则3: 禁止虚假限时限量 (\"最后50单\"必须有真实库存依据)",
    "risk_level": "高",
    "evidence": "主播口播: \"库存只剩最后50单，卖完就没有了!\"; 产品claims包含\"库存告急\"。未提供该库存数量的实时同步数据或系统依据。",
    "fix_suggestion": "若确实仅剩50单，需提供实时库存系统截图或后台数据作为证据，并在直播中告知观众真实库存依据；若无真实依据，立即停止使用该话术。"
  },
  {
    "rule_clause": "规则4: 禁止虚假原价 (划线价必须是近30天内有实际成交的价格)",
    "risk_level": "高",
    "evidence": "产品\"焕白亮肤霜\"标示原价199.0元，现价99.0元。对199.0元划线价，未提供近30天内以该价格真实成交的订单记录。",
    "fix_suggestion": "若199.0元为近30天真实成交价，须保留成交记录备查并在直播间说明；若无法提供，应将划线价调整为近期实际成交均价或删除划线价标示。"
  },
  {
    "rule_clause": "规则5: 必须标注广告标识 (带货内容需在显著位置标注\"广告\")",
    "risk_level": "高",
    "evidence": "直播数据中未提及该直播间或视频流画面标注\"广告\"标识，观看人数达3200人，推测未在显著位置展示广告字样。",
    "fix_suggestion": "立即在直播间画面显著位置（如底部文字、角标）添加\"广告\"字样，确保观众清晰可见，符合广告标记要求。"
  }
]
```
